c(z.custom((v) => {
    if (typeof v !== 'object' || v === null || Array.isArray(v)) return false;
    for (const [k, val] of Object.entries(v as Record<string, unknown>)) {
      if (!/^api\//.test(k)) return false;
      if (typeof val !== 'number' || !Number.isFinite(val)) return false;
    }
    return true;
  }))
